'use client';

import { useMemo, useState } from 'react';
import Link from 'next/link';
import InferenceBadge from '@/components/common/InferenceBadge';
import Card from '@/components/common/Card';
import { useProject } from '@/context/ProjectContext';
import { usePrivacy } from '@/lib/hooks/usePrivacy';
import type { PrivacyExecutionMode } from '@/lib/types/privacy';

interface InferenceResult {
  output: string;
  mode: PrivacyExecutionMode;
  reason: string;
  improvementNote: string | null;
}

const LOCAL_CONFIDENCE_THRESHOLD = 0.6;

async function logRemoteUsage(projectId: string, reason: string): Promise<void> {
  await fetch('/api/privacy/events', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      projectId,
      mode: 'remote',
      reason,
      connector: 'inference',
    }),
  });
}

function inferLocally(prompt: string): string {
  return `Local-only result: ${prompt.slice(0, 180) || 'No prompt provided.'}`;
}

function inferRemotely(prompt: string): string {
  return `Remote-assisted result: ${prompt.slice(0, 180) || 'No prompt provided.'}`;
}

export default function Home() {
  const { projectId, project } = useProject();
  const { settings } = usePrivacy(projectId);
  const [prompt, setPrompt] = useState('Summarize progress and blockers for this feature area.');
  const [localConfidence, setLocalConfidence] = useState(0.4);
  const [result, setResult] = useState<InferenceResult | null>(null);
  const [isRunning, setIsRunning] = useState(false);

  const hasConsent = settings?.remoteInferenceEnabled === true;

  const confidenceLabel = useMemo(() => {
    return `${Math.round(localConfidence * 100)}%`;
  }, [localConfidence]);

  async function runInference() {
    if (!projectId) return;

    setIsRunning(true);

    const isLowConfidence = localConfidence < LOCAL_CONFIDENCE_THRESHOLD;

    if (isLowConfidence && hasConsent) {
      const reason = 'Low confidence and explicit project consent allow remote execution.';
      const output = inferRemotely(prompt);
      await logRemoteUsage(projectId, reason);
      setResult({
        output,
        mode: 'remote',
        reason,
        improvementNote: null,
      });
      setIsRunning(false);
      return;
    }

    const consentBlocked = isLowConfidence && !hasConsent;
    const reason = consentBlocked
      ? 'Project consent missing; remote execution is blocked.'
      : 'Local confidence meets threshold; keeping execution local.';

    const improvementNote = consentBlocked
      ? 'Remote inference is currently denied for this project. Enable consent in Privacy Settings to improve low-confidence outputs.'
      : null;

    setResult({
      output: inferLocally(prompt),
      mode: 'local',
      reason,
      improvementNote,
    });

    setIsRunning(false);
  }

  return (
    <div className="space-y-6">
      <div className="flex items-end justify-between gap-4">
        <div>
          <h2 className="text-xl font-bold text-gray-900 dark:text-white">Inference Preview</h2>
          <p className="text-sm text-gray-500 dark:text-gray-400">
            Project: {project?.name ?? 'No project selected'}
          </p>
        </div>
        <Link
          href="/settings/privacy"
          className="rounded-md border border-gray-300 bg-white px-3 py-1.5 text-sm font-medium text-gray-700 hover:bg-gray-50"
        >
          Open Privacy Center
        </Link>
      </div>

      <Card className="p-5" title="Run Local/Remote Decision" subtitle="Low confidence can use remote only with explicit consent">
        <div className="space-y-4">
          <label className="block text-sm text-gray-700 dark:text-gray-300">
            Prompt
            <textarea
              className="mt-1 w-full rounded-md border border-gray-300 bg-white px-3 py-2 text-sm text-gray-900"
              rows={3}
              value={prompt}
              onChange={event => setPrompt(event.target.value)}
            />
          </label>

          <div>
            <div className="flex items-center justify-between text-sm text-gray-700 dark:text-gray-300">
              <span>Local confidence</span>
              <span>{confidenceLabel}</span>
            </div>
            <input
              type="range"
              min={0}
              max={1}
              step={0.01}
              value={localConfidence}
              onChange={event => setLocalConfidence(Number(event.target.value))}
              className="mt-2 w-full"
            />
            <p className="mt-1 text-xs text-gray-500 dark:text-gray-400">
              Threshold: {Math.round(LOCAL_CONFIDENCE_THRESHOLD * 100)}%
            </p>
          </div>

          <div className="flex items-center gap-3">
            <button
              type="button"
              onClick={runInference}
              disabled={!projectId || isRunning}
              className="rounded-md bg-blue-600 px-3 py-1.5 text-sm font-medium text-white hover:bg-blue-700 disabled:cursor-not-allowed disabled:opacity-60"
            >
              {isRunning ? 'Running...' : 'Run inference'}
            </button>
            {!hasConsent && (
              <p className="text-xs text-amber-700 dark:text-amber-200">
                Remote inference is disabled for this project.
              </p>
            )}
          </div>
        </div>
      </Card>

      {result && (
        <Card className="p-5" title="Result" subtitle="Provenance and deny-path messaging">
          <div className="space-y-3">
            <InferenceBadge mode={result.mode} reason={result.reason} />
            <p className="text-sm text-gray-800 dark:text-gray-100">{result.output}</p>
            {result.improvementNote && (
              <p className="rounded-md border border-amber-200 bg-amber-50 px-3 py-2 text-sm text-amber-800 dark:border-amber-700 dark:bg-amber-900/30 dark:text-amber-100">
                {result.improvementNote}
              </p>
            )}
          </div>
        </Card>
      )}
    </div>
  );
}

